BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?pkgName ?child ?childType ?childName WHERE {
  ?root vocab:NamedElement_name ?pkgName .
  FILTER(CONTAINS(LCASE(STR(?pkgName)), LCASE("Dynamic Power Analaysis"))) .
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?pkg } 
  FILTER EXISTS {
    ?root vocab:Element_ownedElement+ ?pkg .
  }
  ?pkg vocab:NamedElement_name ?childName .
  FILTER(CONTAINS(LCASE(STR(?childName)), LCASE("05 Simulation Configuraitons"))) .
  ?pkg vocab:Element_ownedElement+ ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?pkgName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name ?pkgName .
  FILTER(CONTAINS(LCASE(STR(?pkgName)), LCASE("Dynamic Power")))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?pkgName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name ?pkgName .
  FILTER(
    CONTAINS(LCASE(STR(?pkgName)), LCASE("power")) &&
    (CONTAINS(LCASE(STR(?pkgName)), LCASE("dynamic")) || CONTAINS(LCASE(STR(?pkgName)), LCASE("analays")) || CONTAINS(LCASE(STR(?pkgName)), LCASE("analysis")))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?simPkg ?simName ?conf ?confType ?confName WHERE {
  VALUES ?dynPkg { 
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis>
  }
  ?dynPkg vocab:packagedElement+ ?simPkg .
  ?simPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?simName .
  FILTER(CONTAINS(LCASE(STR(?simName)), LCASE("05 Simulation Configur")))

  ?simPkg vocab:packagedElement+ ?conf .
  ?conf rdf:type ?confType .
  OPTIONAL { ?conf vocab:NamedElement_name ?confName . }
  FILTER(
    ?confType != vocab:package || true
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?simPkg ?simName ?conf ?confType ?confName WHERE {
  VALUES ?dynPkg { 
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis>
  }
  ?dynPkg (vocab:Element_ownedElement|vocab:Package_packagedElement)+ ?simPkg .

  ?simPkg rdf:type vocab:package ;
          vocab:NamedElement_name ?simName .
  FILTER(CONTAINS(LCASE(STR(?simName)), LCASE("simulation")))
  FILTER(CONTAINS(LCASE(STR(?simName)), LCASE("config")) || CONTAINS(LCASE(STR(?simName)), LCASE("configur")))

  ?simPkg vocab:packagedElement+ ?conf .
  OPTIONAL { ?conf vocab:NamedElement_name ?confName . }
  ?conf rdf:type ?confType .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depType ?client ?clientName ?supplier ?supplierName WHERE {
  VALUES ?rootPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis>
  }

  ?rootPkg vocab:Element_ownedElement+ ?elem .
  {
    ?dep rdf:type ?depType ; vocab:Dependency_client ?client ; vocab:Dependency_supplier ?supplier .
  }
  FILTER(?depType IN (vocab:dependency, vocab:allocate, vocab:satisfy, vocab:verify, vocab:refine, vocab:usage))

  OPTIONAL { ?client vocab:NamedElement_name ?clientName . }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName . }

  FILTER(
    (BOUND(?clientName) && CONTAINS(LCASE(STR(?clientName)), LCASE("config"))) ||
    (BOUND(?supplierName) && CONTAINS(LCASE(STR(?supplierName)), LCASE("config"))) ||
    (BOUND(?clientName) && CONTAINS(LCASE(STR(?clientName)), LCASE("simulation"))) ||
    (BOUND(?supplierName) && CONTAINS(LCASE(STR(?supplierName)), LCASE("simulation")))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?elemType ?elemName WHERE {
  VALUES ?rootPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Dynamic%2520Power%2520Analysis>
  }
  ?rootPkg (vocab:Element_ownedElement|vocab:Package_packagedElement)+ ?elem .
  ?elem rdf:type ?elemType .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName . }
  FILTER(
    ?elemType IN (vocab:simulation%20configuration, vocab:Simulation%20Configuration)
  )
}
LIMIT 25
